# --- Worker Threads (Background Tasks) ---

class DownloadWorker(QThread):
    progress   = Signal(int, int, float)  # downloaded_mb, total_mb, bytes_per_sec
    finished   = Signal(str)              # path to completed file
    error      = Signal(str)
    resuming   = Signal(int, int)         # already_mb, total_mb  (emitted once when resuming)

    def __init__(self, url, dest_folder):
        super().__init__()
        self.url = url
        self.dest_folder = dest_folder

    def run(self):
        import requests
        try:
            os.makedirs(self.dest_folder, exist_ok=True)

            local_filename = self.url.split('/')[-1]
            if not local_filename.endswith('.iso'):
                local_filename = "linux_distro.iso"
            full_path = os.path.join(self.dest_folder, local_filename)

            # check for a resumable partial file
            existing_bytes = 0
            if os.path.exists(full_path):
                existing_bytes = os.path.getsize(full_path)

            headers = {}
            if existing_bytes > 0:
                headers['Range'] = f'bytes={existing_bytes}-'

            response = requests.get(self.url, stream=True, timeout=10, headers=headers)

            # 416 = server understood Range but file is already complete
            if response.status_code == 416:
                self.finished.emit(full_path)
                return

            response.raise_for_status()

            # Did the server honor the Range request?
            resuming = (response.status_code == 206)
            if not resuming:
                # Server ignored Range – start fresh
                existing_bytes = 0

            total_length = response.headers.get('content-length')
            if total_length is None:
                self.error.emit("Could not determine file size.")
                return

            # content-length is the number of bytes *in this response*
            response_bytes = int(total_length)
            total_bytes    = existing_bytes + response_bytes
            total_mb       = total_bytes // (1024 * 1024)

            if resuming and existing_bytes > 0:
                self.resuming.emit(existing_bytes // (1024 * 1024), total_mb)

            dl         = existing_bytes          # bytes downloaded so far (including what was already on disk)
            new_bytes  = 0                       # bytes received in this session (for speed calc)
            start_time = time.monotonic()

            open_mode = 'ab' if resuming else 'wb'
            with open(full_path, open_mode) as f:
                for chunk in response.iter_content(chunk_size=65536):
                    if chunk:
                        f.write(chunk)
                        dl         += len(chunk)
                        new_bytes  += len(chunk)
                        current_mb  = dl // (1024 * 1024)
                        elapsed     = time.monotonic() - start_time
                        bps         = new_bytes / elapsed if elapsed > 0 else 0
                        self.progress.emit(current_mb, total_mb, bps)

            self.finished.emit(full_path)

        except Exception as e:
            self.error.emit(str(e))


class HashWorker(QThread):
    # Computes SHA-256 of a file in chunks, emitting progress, 
    # then compares against the expected hash fetched from checksum_url.
    progress  = Signal(int)   # 0-100
    passed    = Signal()
    failed    = Signal(str)   # human-readable reason

    def __init__(self, iso_path, checksum_url, iso_filename):
        super().__init__()
        self.iso_path      = iso_path
        self.checksum_url  = checksum_url
        self.iso_filename  = iso_filename   # bare filename to match inside checksum file

    def run(self):
        import requests, hashlib

        # 1. Fetch the checksum file
        try:
            r = requests.get(self.checksum_url, timeout=15)
            r.raise_for_status()
            checksum_text = r.text
        except Exception as e:
            self.failed.emit(f"Could not fetch checksum file:\n{e}")
            return

        # 2. Parse out the expected hash
        # Standard format is either:
        #    <hash>  <filename>       (sha256sum / Ubuntu / Mint style)
        #    <hash>  *<filename>      (binary flag)
        #    <hash>                   (file contains only the hash, Zorin style)
        expected_hash = None
        for line in checksum_text.splitlines():
            line = line.strip()
            if not line or line.startswith('#'):
                continue
            parts = line.split()
            if len(parts) == 1:
                # Whole file is just the hash
                expected_hash = parts[0].lower()
                break
            # parts[1] may be  filename  or  *filename
            fname = parts[1].lstrip('*').strip()
            if fname == self.iso_filename or fname == os.path.basename(self.iso_path):
                expected_hash = parts[0].lower()
                break

        if not expected_hash:
            self.failed.emit(
                f"Could not find a checksum for '{self.iso_filename}' "
                f"in the checksum file."
            )
            return

        # 3. Hash the ISO
        try:
            iso_size  = os.path.getsize(self.iso_path)
            sha256    = hashlib.sha256()
            processed = 0
            chunk_sz  = 1024 * 1024   # 1 MB
            with open(self.iso_path, 'rb') as f:
                while True:
                    chunk = f.read(chunk_sz)
                    if not chunk:
                        break
                    sha256.update(chunk)
                    processed += len(chunk)
                    pct = int((processed / iso_size) * 100) if iso_size else 0
                    self.progress.emit(pct)
        except Exception as e:
            self.failed.emit(f"Could not read ISO file:\n{e}")
            return

        actual_hash = sha256.hexdigest().lower()

        if actual_hash == expected_hash:
            self.passed.emit()
        else:
            self.failed.emit(
                "The downloaded file appears to be corrupt or incomplete.\n"
                "Please delete it and try again."
            )

class BurnWorker(QThread):
    progress = Signal(int, float) # percent, bytes_per_sec
    finished = Signal()
    error = Signal(str)

    def __init__(self, iso_path, drive_letter, physical_drive_path):
        super().__init__()
        self.iso_path = iso_path
        self.drive_letter = drive_letter
        self.physical_drive_path = physical_drive_path

    def run(self):
        try:
            if not os.path.exists(self.iso_path):
                self.error.emit("ISO file not found.")
                return

            # 1. Wipe the partition table
            # Force Windows to release its grip on any foreign partitions
            # currently on the drive.
            self.progress.emit(0, 0.0) # Start at 0
            
            # Extract the disk number (e.g., from \\.\PHYSICALDRIVE2 -> 2)
            # This regex finds the last number in the string
            match = re.search(r"PHYSICALDRIVE(\d+)$", self.physical_drive_path)
            if not match:
                self.error.emit("Could not determine disk number.")
                return
            
            disk_num = match.group(1)
            
            # Run the wipe
            wipe_success, wipe_msg = self.wipe_drive_with_diskpart(disk_num)
            if not wipe_success:
                self.error.emit(f"Failed to clear drive: {wipe_msg}")
                return

            # Short pause to let Windows refresh its device list
            time.sleep(2)

            # 2. RAW write
            iso_size = os.path.getsize(self.iso_path)
            start_time = time.monotonic()
            
            with open(self.iso_path, 'rb') as iso_file:
                # Open the physical drive again. 
                # Now that it's "clean", Windows treats it as a raw, empty device with no conflicting handles
                with open(self.physical_drive_path, 'r+b') as device_file:
                    copied = 0
                    chunk_size = 1024 * 1024  # 1MB chunks
                    
                    while True:
                        data = iso_file.read(chunk_size)
                        if not data:
                            break
                        device_file.write(data)
                        copied += len(data)
                        
                        percent = int((copied / iso_size) * 100)
                        elapsed = time.monotonic() - start_time
                        bps = copied / elapsed if elapsed > 0 else 0
                        self.progress.emit(percent, bps)
                        
            self.finished.emit()

        except PermissionError:
            self.error.emit("Access Denied. Please run as Administrator.")
        except Exception as e:
            self.error.emit(f"Write error: {str(e)}")

    def wipe_drive_with_diskpart(self, disk_num):
        # Robustly wipes the drive using diskpart with retries
        max_retries = 3
        
        # Use 'noerr' to prevent script abort, but the text output 
        # still contains the word "error", which we must ignore
        script_cmds = [
            f"select disk {disk_num}",
            "attributes disk clear readonly", # unlock read-only drives
            "online disk noerr",              # ensure it's online
            "clean",                          # THE IMPORTANT PART
            "rescan"
        ]
        
        script_content = "\n".join(script_cmds)
        
        # Temp script file
        script_path = os.path.join(os.environ['TEMP'], f'iwantlinux_wipe_{disk_num}.txt')
        
        last_output = ""

        for attempt in range(1, max_retries + 1):
            try:
                with open(script_path, "w") as f:
                    f.write(script_content)
                
                startupinfo = subprocess.STARTUPINFO()
                startupinfo.dwFlags |= subprocess.STARTF_USESHOWWINDOW
                
                process = subprocess.Popen(
                    ["diskpart", "/s", script_path],
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE,
                    startupinfo=startupinfo,
                    text=True 
                )
                stdout, stderr = process.communicate()
                last_output = stdout + stderr

                # Did it explicitly say the disk is online?
                if "This disk is already online" in last_output:
                    return True, "Success"
                # 2. If not, did it fail?
                # We wait and retry.
                time.sleep(2)
                
            except Exception as e:
                last_output = str(e)
                time.sleep(2)
            finally:
                if os.path.exists(script_path):
                    try:
                        os.remove(script_path)
                    except:
                        pass
        
        return False, f"DiskPart failed after {max_retries} attempts.\nOutput: {last_output}"
        
# --- UI Components ---

class DistroCard(QFrame):
    def __init__(self, name, desc, base64_data, parent=None):
        super().__init__(parent)
        self.setCursor(Qt.PointingHandCursor)
        self.setObjectName("DistroCard")
        # Fixed size for grid consistency
        self.setFixedSize(250, 150)
        self.setStyleSheet("""
                #DistroCard { 
                    background-color: #ffffff; 
                    border: 2px solid #dceef9; 
                    border-radius: 18px;
                }
            """)
        
        layout = QVBoxLayout(self)
        layout.setContentsMargins(12, 14, 12, 14)
        layout.setSpacing(8)
        layout.setAlignment(Qt.AlignCenter)

        # 1. Logo Image
        self.icon_label = QLabel()
        self.icon_label.setFixedSize(48, 48)
        self.icon_label.setAlignment(Qt.AlignCenter)
        
        # Decode Base64 to Pixmap
        if base64_data and len(base64_data) > 50: # Simple check if data exists
            byte_data = QByteArray.fromBase64(base64_data.encode())
            pixmap = QPixmap()
            pixmap.loadFromData(byte_data)
            # Scale it smoothly to fit the label
            self.icon_label.setPixmap(pixmap.scaled(48, 48, Qt.KeepAspectRatio, Qt.SmoothTransformation))
        else:
            # Fallback if Base64 is missing (Gray circle with letter)
            self.icon_label.setText(name[0])
            self.icon_label.setStyleSheet("background-color: #c2e6fb; color: #1a6faa; border-radius: 28px; font-size: 26px; font-weight: bold;")

        # 2. Distro Name
        self.lbl_name = QLabel(name)
        self.lbl_name.setStyleSheet("font-size: 17px; font-weight: 800; color: #1a2e3d; margin-top: 2px;")
        self.lbl_name.setAlignment(Qt.AlignCenter)

        # 3. Description
        self.lbl_desc = QLabel(desc)
        self.lbl_desc.setWordWrap(True)
        self.lbl_desc.setAlignment(Qt.AlignCenter)
        self.lbl_desc.setStyleSheet("color: #4a6070; font-size: 12px;")

        layout.addWidget(self.icon_label, alignment=Qt.AlignCenter)
        layout.addWidget(self.lbl_name)
        layout.addWidget(self.lbl_desc)

    def set_selected(self, selected):
        if selected:
            self.setStyleSheet("""
                #DistroCard { 
                    background: qlineargradient(x1:0, y1:0, x2:1, y2:0,
                    stop:0 #5bb8f5, stop:1 #2a8fd4); 
                    border: 3px solid #2a8fd4; 
                    border-radius: 18px;
                }
            """)
            self.lbl_name.setStyleSheet("font-size: 17px; font-weight: 800; color: #ffffff; margin-top: 2px;")
            self.lbl_desc.setStyleSheet("color: #ffffff; font-size: 12px;")
        else:
            self.setStyleSheet("""
                #DistroCard { 
                    background-color: #ffffff; 
                    border: 2px solid #dceef9; 
                    border-radius: 18px;
                }
            """)
            self.lbl_name.setStyleSheet("font-size: 17px; font-weight: 800; color: #1a2e3d; margin-top: 2px;")
            self.lbl_desc.setStyleSheet("color: #4a6070; font-size: 12px;")
            
class Page1_Selection(QWidget):
    distro_selected = Signal(dict)

    def __init__(self):
        super().__init__()
        self.setStyleSheet("background-color: #e8f6ff;")
        layout = QVBoxLayout(self)
        layout.setContentsMargins(40, 28, 40, 20)
        layout.setSpacing(0)
        
        title = QLabel("Choose Your New Operating System")
        title.setStyleSheet("font-size: 24px; font-weight: 800; color: #1a2e3d; margin-bottom: 4px;")
        title.setAlignment(Qt.AlignCenter)
        layout.addWidget(title)

        subtitle = QLabel("Select a version of Linux to get started.")
        subtitle.setStyleSheet("font-size: 13px; color: #4a6070; margin-bottom: 20px;")
        subtitle.setAlignment(Qt.AlignCenter)
        layout.addWidget(subtitle)

        # Grid layout for cards
        grid_container = QWidget()
        grid_container.setStyleSheet("background: transparent;")
        self.grid = QGridLayout(grid_container)
        self.grid.setSpacing(16)
        self.grid.setAlignment(Qt.AlignCenter)

        self.cards = []
        
        for i, d in enumerate(DISTROS):
            # Pass the base64 string here
            card = DistroCard(d['name'], d['desc'], d.get('logo_b64', ""))
            card.mousePressEvent = lambda e, data=d, c=card: self.select_distro(data, c)
            
            # Smart Grid placement (2 columns)
            row = i // 2
            col = i % 2
            self.grid.addWidget(card, row, col)
            self.cards.append(card)
            
        layout.addWidget(grid_container)
        layout.addStretch()

    def select_distro(self, data, active_card):
        for c in self.cards:
            c.set_selected(False)
        active_card.set_selected(True)
        self.distro_selected.emit(data)

    def clear_selection(self):
        for c in self.cards:
            c.set_selected(False)
            
